package com.quinicastock.inventory.repository; import com.quinicastock.common.lib.entity.*; import org.springframework.data.jpa.repository.JpaRepository; import java.util.List; import java.util.UUID; public interface ProductRepository extends JpaRepository<Product, UUID> { List<Product> findByTenantId(UUID tenantId); } public interface CategoryRepository extends JpaRepository<Category, UUID> { List<Category> findByTenantId(UUID tenantId); } public interface SaleRepository extends JpaRepository<Sale, UUID> { List<Sale> findByTenantId(UUID tenantId); } public interface SupplierRepository extends JpaRepository<Supplier, UUID> { List<Supplier> findByTenantId(UUID tenantId); }